CREATE MATERIALIZED VIEW report.service_subscription_info AS SELECT sp.account_id, sp.subscription_id, sp.plan_id, bt.term, p.plan_name, pf.units_included, pf.units_increment, pf.price_increment, sp.cancelled_at FROM public.subscriptions sp JOIN public.plans p USING (plan_id) JOIN public.plan_details pd USING (plan_id) JOIN public.pricing_fees pf USING (plan_detail_id) JOIN public.features f USING (feature_id) JOIN public.billing_terms bt USING (billing_term_id) WHERE (sp.cancelled_at IS NULL OR sp.cancelled_at > CURRENT_TIMESTAMP) AND f.feature_name = 'notifications'::text ORDER BY sp.cancelled_at DESC, sp.started_at WITH NO DATA
